INSERT INTO novels (title, description, genre, content, context_memory, style_guide, word_count, created_at, updated_at) VALUES
('剑破苍穹', '一个平凡少年通过不懈努力，成为一代剑神的故事', '玄幻', '', '主角：叶凡，平凡少年，有毅力，有天赋\n世界观：修真世界，等级分为练气、筑基、金丹、元婴、化神\n门派：青云门，正道第一大派', '语言风格：大气磅礴，画面感强，动作描写细腻', 0, NOW(), NOW());
INSERT INTO chapters (novel_id, title, chapter_number, content, word_count, created_at, updated_at) VALUES
((SELECT id FROM novels WHERE title = '剑破苍穹'), '第一章 平凡少年', 1, '叶凡站在青阳城的街头，看着来来往往的人群，心中充满了不甘。他是一个平凡的少年，父母都是普通的农民，家里很穷。但是他有一个梦想，那就是成为一名修真者，拥有强大的力量，保护自己的家人。\n\n这一天，青云门的招生弟子来到了青阳城，叶凡早早地就去排队了。他知道，这是他改变命运的机会。\n\n轮到叶凡的时候，招生弟子看了他一眼，皱了皱眉头。"资质一般，不过有毅力，勉强收下吧。"\n\n叶凡听到这句话，心中大喜。他终于成为了青云门的一名外门弟子。', 300, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '剑破苍穹'), '第二章 初入青云', 2, '叶凡跟着招生弟子来到了青云门。青云门位于青云山上，周围云雾缭绕，仿佛仙境一般。\n\n外门弟子的生活很艰苦，每天都要早起修炼，还要做各种杂活。但是叶凡并不觉得苦，他知道，只有付出才有回报。\n\n三个月后，叶凡迎来了第一次测试。测试的内容是考核弟子的修为。叶凡凭借着自己的努力，成功通过了测试，成为了一名内门弟子。\n\n成为内门弟子后，叶凡获得了更多的资源和指导，他的修为进步得更快了。', 280, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '剑破苍穹'), '第三章 奇遇', 3, '叶凡在一次外出任务中，遇到了一只受伤的白虎。他不忍心看到白虎受苦，便出手相救。\n\n没想到，这只白虎是一只神兽，它为了感谢叶凡的救命之恩，送给了他一颗洗髓丹。\n\n叶凡服用了洗髓丹后，资质得到了极大的提升，修炼速度也变得更快了。\n\n这一天，叶凡在修炼时，突然感觉到一股强大的力量从体内涌出。他知道，自己突破了，成为了一名筑基期修士。', 290, NOW(), NOW());
INSERT INTO novels (title, description, genre, content, context_memory, style_guide, word_count, created_at, updated_at) VALUES
('都市传奇', '一个普通大学生意外获得超能力，从此开启了不平凡的人生', '都市', '', '主角：林风，普通大学生，善良，有正义感\n超能力：能够读取他人的思想\n背景：现代都市，充满了各种机遇和挑战', '语言风格：现代感强，贴近生活，对话自然', 0, NOW(), NOW());
INSERT INTO chapters (novel_id, title, chapter_number, content, word_count, created_at, updated_at) VALUES
((SELECT id FROM novels WHERE title = '都市传奇'), '第一章 意外获得超能力', 1, '林风是一名普通的大学生，每天过着三点一线的生活。直到有一天，他在图书馆看书时，突然感到一阵头痛，然后就晕了过去。\n\n当他醒来时，发现自己能够听到周围人的心声。他以为自己出现了幻觉，但是经过多次验证，他确定自己真的获得了读取他人思想的超能力。\n\n起初，林风对这个超能力感到很兴奋，但是很快他就发现，这个超能力也给他带来了很多麻烦。他能够听到很多不想听到的声音，这让他感到很困扰。', 290, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '都市传奇'), '第二章 第一次使用超能力', 2, '林风逐渐适应了自己的超能力，他开始尝试用这个超能力帮助别人。\n\n一天，他在公交车上听到一个小偷的心声，知道他要偷一位老人的钱包。林风及时出手，阻止了小偷的行为。\n\n老人很感激林风，想要给他一些报酬，但是林风拒绝了。他觉得，用自己的能力帮助别人是一件很有意义的事情。\n\n这件事情让林风意识到，自己的超能力可以用来做很多有意义的事情。', 280, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '都市传奇'), '第三章 遇到麻烦', 3, '林风的超能力引起了一些人的注意。有一天，他被一群神秘人绑架了。\n\n这些神秘人想要研究林风的超能力，他们对林风进行了各种测试。\n\n林风在被绑架期间，听到了这些人的心声，知道他们想要用自己的超能力做坏事。他决定想办法逃脱。\n\n经过一番努力，林风终于成功逃脱了。但是他知道，自己的麻烦才刚刚开始。', 290, NOW(), NOW());
INSERT INTO novels (title, description, genre, content, context_memory, style_guide, word_count, created_at, updated_at) VALUES
('星际探索', '人类探索宇宙的故事，充满了未知和挑战', '科幻', '', '主角：李明，宇航员，勇敢，聪明\n背景：未来世界，人类已经开始探索宇宙\n科技：星际飞船，人工智能，外星文明', '语言风格：科技感强，想象力丰富，逻辑严谨', 0, NOW(), NOW());
INSERT INTO chapters (novel_id, title, chapter_number, content, word_count, created_at, updated_at) VALUES
((SELECT id FROM novels WHERE title = '星际探索'), '第一章 出发', 1, '李明站在星际飞船的控制室里，看着窗外的星空，心中充满了激动。这是人类第一次前往半人马座α星的任务，他作为队长，责任重大。\n\n飞船缓缓启动，离开了地球的引力范围。李明知道，这趟旅程需要花费7年的时间，他们将在低温休眠中度过大部分时间。\n\n在休眠前，李明最后看了一眼地球的方向，心中默默祈祷："希望我们能够成功完成任务，为人类的未来开辟新的道路。"', 270, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '星际探索'), '第二章 意外发现', 2, '7年后，飞船到达了半人马座α星。李明和他的团队醒来后，开始对周围的环境进行探测。\n\n他们发现了一颗类地行星，这颗行星上有大气层和液态水，看起来很适合人类居住。\n\n就在他们准备着陆的时候，突然收到了一个神秘的信号。这个信号看起来是人工发出的，这意味着这颗行星上可能存在外星文明。\n\n李明和他的团队既兴奋又紧张，他们不知道等待他们的会是什么。', 280, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '星际探索'), '第三章 第一次接触', 3, '李明和他的团队降落在了这颗行星上。他们小心翼翼地探索着周围的环境，寻找信号的来源。\n\n突然，他们看到了一群外星人。这些外星人和人类很相似，但是他们的皮肤是蓝色的，眼睛很大。\n\n起初，双方都很紧张，但是很快他们就建立了沟通。这些外星人告诉李明，他们是这颗行星的原住民，已经在这里生活了数万年。\n\n李明和他的团队与这些外星人建立了友好的关系，他们互相学习，互相交流。这是人类第一次与外星文明接触，意义重大。', 290, NOW(), NOW());
INSERT INTO novels (title, description, genre, content, context_memory, style_guide, word_count, created_at, updated_at) VALUES
('江湖恩怨', '一个武侠世界中的恩怨情仇，充满了刀光剑影', '武侠', '', '主角：乔峰，丐帮帮主，正直，武功高强\n背景：南宋时期，江湖动荡，各大门派之间矛盾重重\n门派：丐帮，少林，武当，峨眉', '语言风格：古风浓郁，打斗描写精彩，人物形象鲜明', 0, NOW(), NOW());
INSERT INTO chapters (novel_id, title, chapter_number, content, word_count, created_at, updated_at) VALUES
((SELECT id FROM novels WHERE title = '江湖恩怨'), '第一章 丐帮大会', 1, '乔峰站在丐帮大会的台上，接受着众弟子的朝拜。他是丐帮的新任帮主，年轻有为，武功高强。\n\n突然，一个黑衣人闯了进来，声称乔峰是契丹人，不是汉人。这个消息在丐帮中引起了轩然大波。\n\n乔峰感到很震惊，他从小就在丐帮长大，一直认为自己是汉人。但是黑衣人拿出了证据，证明乔峰的父母是契丹人。\n\n丐帮弟子们开始怀疑乔峰，一些人甚至想要推翻他的帮主之位。', 280, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '江湖恩怨'), '第二章 真相', 2, '乔峰为了查明自己的身世，离开了丐帮，开始了寻找真相的旅程。\n\n他来到了雁门关，找到了当年参与雁门关之战的人，了解到了事情的真相。\n\n原来，乔峰的父母是契丹人，但是他们并没有做过任何坏事。当年的雁门关之战是一场误会，乔峰的父母被冤枉了。\n\n乔峰知道真相后，感到很痛苦。他不知道自己应该站在汉人这边还是契丹人这边。', 270, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '江湖恩怨'), '第三章 大义', 3, '乔峰在寻找真相的过程中，发现了一个更大的阴谋。有人想要挑起宋辽之间的战争，从中渔利。\n\n乔峰决定阻止这个阴谋，他不想看到宋辽之间发生战争，让无数无辜的人死去。\n\n他分别找到了宋朝皇帝和辽国皇帝，说服他们不要发动战争。最终，宋辽两国签订了和平协议，避免了一场血光之灾。\n\n乔峰虽然不是汉人，但是他的大义之举赢得了所有人的尊敬。他成为了宋辽两国的英雄。', 290, NOW(), NOW());
INSERT INTO novels (title, description, genre, content, context_memory, style_guide, word_count, created_at, updated_at) VALUES
('心动瞬间', '一个关于爱情的故事，充满了甜蜜和感动', '言情', '', '主角：林小雨，大学生，活泼开朗\n男主角：陈阳，大学生，阳光帅气\n背景：大学校园，充满了青春和活力', '语言风格：清新自然，情感细腻，描写生动', 0, NOW(), NOW());
INSERT INTO chapters (novel_id, title, chapter_number, content, word_count, created_at, updated_at) VALUES
((SELECT id FROM novels WHERE title = '心动瞬间'), '第一章 初次相遇', 1, '林小雨在图书馆里看书，突然一个男生走了过来，坐在了她的对面。这个男生阳光帅气，林小雨不禁多看了他几眼。\n\n男生注意到了林小雨的目光，对她笑了笑。林小雨感到很害羞，低下了头。\n\n过了一会儿，男生离开了，但是他忘记了带走自己的书。林小雨拿起书，想要还给男生。\n\n她在图书馆里找了很久，终于找到了男生。男生很感谢林小雨，自我介绍说他叫陈阳。\n\n从那天开始，林小雨和陈阳成为了朋友。', 280, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '心动瞬间'), '第二章 渐生情愫', 2, '林小雨和陈阳经常一起上课，一起吃饭，一起图书馆学习。他们之间的关系越来越亲密。\n\n有一天，陈阳邀请林小雨去看电影。电影结束后，他们一起散步回宿舍。\n\n在月光下，陈阳突然牵起了林小雨的手。林小雨的心跳加速，她知道自己喜欢上了陈阳。\n\n陈阳对林小雨说："我喜欢你，做我女朋友吧。"\n\n林小雨害羞地点了点头，他们正式成为了情侣。', 270, NOW(), NOW()),
((SELECT id FROM novels WHERE title = '心动瞬间'), '第三章 甜蜜时光', 3, '林小雨和陈阳成为情侣后，度过了很多甜蜜的时光。他们一起去看日出，一起去逛街，一起去旅行。\n\n有一天，陈阳带林小雨去了一个特别的地方。那是一个山顶，可以看到整个城市的风景。\n\n陈阳对林小雨说："我会一直爱你，直到永远。"\n\n林小雨感动得流下了眼泪，她知道自己找到了真爱。\n\n他们在山顶上拥吻，许下了彼此的承诺。', 260, NOW(), NOW());
